rag_with_kg.sparql:
PREFIX ex: <http://example.org/ai-kg/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
SELECT DISTINCT ?org ?orgLabel ?areaLabel WHERE {
  ?org ex:hasResearchArea ?area .
  ?area rdfs:label ?areaLabel .
  FILTER(CONTAINS(LCASE(STR(?areaLabel)), "machine learning"))
  OPTIONAL { ?org rdfs:label ?orgLabel }
}
LIMIT 10

PREFIX ex: <http://example.org/ai-kg/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
SELECT DISTINCT ?partner ?partnerLabel WHERE {
  ?cnrs rdfs:label ?cnrsLabel .
  FILTER(CONTAINS(LCASE(STR(?cnrsLabel)), "cnrs"))
  { ?cnrs ex:collaboratesWith ?partner } UNION { ?partner ex:collaboratesWith ?cnrs }
  OPTIONAL { ?partner rdfs:label ?partnerLabel }
}
LIMIT 10

PREFIX ex: <http://example.org/ai-kg/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
SELECT DISTINCT ?icml ?area ?areaLabel WHERE {
  ?icml ex:hasResearchArea ?area .
  FILTER(CONTAINS(LCASE(STR(?icml)), "icml"))
  OPTIONAL { ?area rdfs:label ?areaLabel }
}
LIMIT 10

PREFIX ex: <http://example.org/ai-kg/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
SELECT DISTINCT ?target ?targetLabel ?partner ?partnerLabel WHERE {
  OPTIONAL { ?target rdfs:label ?targetLabel }
  FILTER(CONTAINS(LCASE(STR(?target)), "google-deepmind") || CONTAINS(LCASE(STR(COALESCE(?targetLabel, ""))), "google deepmind"))
  { ?target ex:collaboratesWith ?partner } UNION { ?partner ex:collaboratesWith ?target }
  OPTIONAL { ?partner rdfs:label ?partnerLabel }
}
LIMIT 10

PREFIX ex: <http://example.org/ai-kg/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
SELECT DISTINCT ?entity ?entityLabel ?area ?areaLabel WHERE {
  ?entity ex:hasResearchArea ?area .
  OPTIONAL { ?entity rdfs:label ?entityLabel }
  FILTER(CONTAINS(LCASE(STR(?entity)), "cnrs") || CONTAINS(LCASE(STR(COALESCE(?entityLabel, ""))), "cnrs"))
  OPTIONAL { ?area rdfs:label ?areaLabel }
}
LIMIT 10
